import os
import shutil
import tarfile

def extract_tar_file(tar_path, dest_dir):
    try:
        if not os.path.exists(dest_dir):
            os.makedirs(dest_dir)
        
        with tarfile.open(tar_path, 'r') as tar_ref:
            tar_ref.extractall(path=dest_dir)
            
        return True
    except Exception as e:
        print(f"Error: {str(e)}")
        return False

# Example usage
tar_file = input("Enter the path to your tar file: ")
dest_folder = input("Enter the destination directory: ")

if extract_tar_file(tar_file, dest_folder):
    print("Tar file extracted successfully.")
else:
    print("Failed to extract tar file.")